date_compare.dax:
var p = SELECTEDVALUE('Duration Parameter'[Period])
var y = SELECTEDVALUE(Calendar[Year-Month Nb])
var ye = INT(LEFT(y,4))
var mo = INT(RIGHT(y,2))
var maxdate = CALCULATE([max_calendar_date], ALL(Calendar))
var mindate = EOMONTH(maxdate,-13)+1
var max_year = YEAR(maxdate)
var max_month = MONTH(maxdate)
var min_year = YEAR(mindate)
var min_month = MONTH(mindate)
var ytd_ =
IF(
ye = max_year &&
mo >= 1 &&
mo <= max_month,
1,0
)
var L12M =
IF(
(ye = max_year && mo <= max_month-1) ||
(ye = min_year && mo >= min_month) ||
(ye > min_year && ye < max_year),
1,0
)
var DateFilter = 1
var mom_ =
IF(
(ye=max_year && mo=max_month-1) ||
(ye=max_year-1 && max_month=1 && mo=12),
1,0
)
var last2m_ =
IF(
(ye=max_year && mo>=max_month-2 && mo<max_month) ||
(max_month=1 && ye=max_year-1 && mo IN {11,12}) ||
(max_month=2 && ((ye=max_year && mo=1) || (ye=max_year-1 && mo=12))),
1,0
)
RETURN
SWITCH(
p,
"YTD", ytd_,
"L12M", L12M,
"MOM", last2m_,
"Date-Filter", DateFilter
)
